16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT_RATE = 0.2;
22	const LOYALTY_YEARS = 2;
23	const BLOCK_SIZE = 3;
24	const BLOCK_BASE_PREMIUM = 60;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	
37	const countByType = (items: Item[]): Map<string, number> => {
38	  const counts = new Map<string, number>();
39	  for (const item of items) {
40	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
41	  }
42	  return counts;
43	};
44	
45	const componentsBase = (components: Item[]): number => {
46	  let total = 0;
47	  for (const [type, count] of countByType(components)) {
48	    total += count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
49	  }
50	  return total;
51	};
52	
53	const mainItemsBase = (items: Item[]): number =>
54	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
55	
56	const itemSurcharges = (item: Item): number => {
57	  const base = BASE_PREMIUMS[item.type];
58	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
59	  const highEnchant = (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE_RATE : 0;
60	  return curse + highEnchant;
61	};
62	
63	const quotePremium = (step: QuoteStep, customer: Customer): QuoteResult => {
64	  const mainItems = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
65	  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
66	
67	  const policyBase = mainItemsBase(mainItems) + componentsBase(components);
68	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
69	  const surcharges = mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
70	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
71	
72	  return { premium: Math.ceil(policyBase + firstInsurance + surcharges - loyalty + PROCESSING_FEE) };
73	};
74	
75	const DEDUCTIBLE = 100;
76	const CAP_MULTIPLIER = 2;
77	
78	const INSURANCE_VALUES: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const insuranceSum = (items: Item[]): number =>
88	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
89	
90	const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
91	  const cap = insuranceSum(policyItems) * CAP_MULTIPLIER;
92	  const payout = step.incident.damages.reduce(
93	    (sum, d) => sum + Math.max(0, d.amount - DEDUCTIBLE),
94	    0,
95	  );
96	  return { payout: Math.floor(payout), remainingCap: cap - payout };
97	};
