103	      results.push(quotePremium(step, scenario.customer));
104	    } else {
105	      const policyStep = scenario.steps[step.policy] as QuoteStep;
106	      results.push(claimResult(step, policyStep.items));
107	    }
108	  }
109	  return { results };
110	};
