const claimResult = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
  const cap = insuranceSum(policyItems) * CAP_MULTIPLIER;
  const payout = step.incident.damages.reduce(
    (sum, d) => sum + Math.max(0, d.amount - DEDUCTIBLE),
    0,
  );
  return { payout, remainingCap: cap - payout };
};

const policyItemsFor = (step: ClaimStep, steps: Step[]): Item[] => {
  const policyStep = steps[step.policy];
  if (policyStep.op !== "quote") {
    throw new Error(`step ${step.policy} is not a quote`);
  }
  return policyStep.items;
};

export const run = (scenario: Scenario): { results: StepResult[] } => {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push(quotePremium(step, scenario.customer));
    } else {
      results.push(claimResult(step, policyItemsFor(step, scenario.steps)));
    }
  }
  return { results };
};
